// Essence Streams -- three vertical signal channels via an O(1) band-fold. No loops.
uniform vec4 uChan;   // x=streams, y=gutter, z=edgeGlow, w=cellDensity
uniform vec4 uFlow;   // x=flowSpeed, y=filaments, z=shimmer, w=time(=absTime*flowSpeed)
uniform vec4 uLook;   // x=ptpRate, y=syncLine, z=brightness, w=absTime
out vec4 fragColor;
const float PI = 3.14159265;

float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
// cheap 2D value noise (single lookup, smooth) -- no octave loop
float vnoise(vec2 p){
    vec2 i=floor(p), f=fract(p); vec2 u=f*f*(3.0-2.0*f);
    return mix(mix(hash21(i), hash21(i+vec2(1,0)), u.x),
               mix(hash21(i+vec2(0,1)), hash21(i+vec2(1,1)), u.x), u.y);
}

vec3 channelColor(float c){
    if(c < 0.5) return vec3(0.00, 0.85, 1.00);   // cyan video
    if(c < 1.5) return vec3(0.22, 1.00, 0.42);   // green audio
    return vec3(1.00, 0.69, 0.00);               // amber ancillary
}

void main(){
    vec2 uv = vUV.st;             // 0..1, y up
    float nC   = clamp(uChan.x, 1.0, 3.0);
    float gut  = uChan.y;         // gutter (dark gap) width fraction
    float eg   = uChan.z;         // edge glow
    float cd   = uChan.w;         // cell density
    float fspd = uFlow.x;
    float fil  = uFlow.y;
    float shim = uFlow.z;
    float t    = uFlow.w;
    float bright = uLook.z;

    vec3 col = vec3(0.010, 0.012, 0.016);   // near-black ground

    // --- O(1) band-fold: which channel is this pixel in, and where across it ---
    float bandF = uv.x * nC;        // 0..nC
    float ci    = floor(bandF);     // channel index
    float ci_c  = clamp(ci, 0.0, nC-1.0);
    float lx    = fract(bandF);     // 0..1 across the channel

    // gutter mask: dark hairline gaps between channels (and at the frame edges)
    float halfGut = gut*0.5;
    float inBand  = smoothstep(0.0, 0.02, lx-halfGut) * smoothstep(1.0, 0.98, lx+halfGut);
    // crisp channel edge with fwidth for resolution independence
    float aa = fwidth(lx) * 1.5;
    float edgeL = smoothstep(halfGut+aa, halfGut-aa, abs(lx-halfGut));
    float edgeR = smoothstep(halfGut+aa, halfGut-aa, abs(lx-(1.0-halfGut)));

    vec3 cc = channelColor(ci_c);

    // --- flowing content inside the band: scrolled noise + quantized data-cells ---
    // each channel scrolls down at its own speed (the three-rivers cadence)
    float speedJ = mix(0.7, 1.3, hash21(vec2(ci_c, 3.0)));
    float scroll = uv.y + t*speedJ;            // y up, +t scrolls content down past the frame
    // fine filaments: layered cheap noise, no octave loop (two fixed-freq lookups)
    float fa = vnoise(vec2(lx*6.0, scroll*5.0));
    float fb = vnoise(vec2(lx*13.0 + 4.0, scroll*11.0 - 2.0));
    float flow = mix(fa, fb, 0.4);
    float filaments = smoothstep(0.55, 0.9, flow) * fil;
    // quantized data-cells marching down the channel
    float cellY = scroll * mix(8.0, 26.0, cd);
    float cell  = smoothstep(0.15, 0.45, fract(cellY)) * (1.0 - smoothstep(0.55, 0.85, fract(cellY)));
    float cellBright = 0.4 + 0.6*hash21(vec2(floor(cellY), ci_c));
    // caustic shimmer across the surface
    float caustic = 0.5 + 0.5*sin(lx*PI*3.0 + scroll*6.0 + ci_c*2.0);

    float body = (0.18 + 0.5*filaments + 0.5*cell*cellBright) * inBand;
    body += caustic * 0.08 * shim * inBand;
    col += cc * body * bright;
    // bright hairline channel edges (the engineering rule)
    col += cc * (edgeL+edgeR) * 0.5 * eg;
    // white-hot lift on the densest filaments/cells
    col += vec3(1.0) * smoothstep(0.8, 1.0, filaments+cell*cellBright) * inBand * 0.4;

    // --- PTP beat: all three channels flash + a single horizontal sync line sweeps ---
    float beat = fract(uLook.w * uLook.x);
    float flash = pow(max(0.0, 1.0 - beat*4.0), 3.0);
    col *= 1.0 + 0.4*flash;
    float syncY = 1.0 - beat;                  // sweeps top->bottom each beat
    float sline = smoothstep(0.006, 0.0, abs(uv.y - syncY));
    col += vec3(0.6,0.9,1.0) * sline * uLook.y * (0.6+0.4*flash);

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Bright-pass + gaussian blur at 1/4 resolution (cheap, constant at 4K).
uniform vec4 uBloom;   // x=strength, y=threshold, z=blurWidth
out vec4 fragColor;
void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;   // 1/lowW, 1/lowH
    float thr = uBloom.y;
    float bw  = uBloom.z;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 6;
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/22.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*bw).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    fragColor = vec4((sum/max(wsum,1e-4)) * uBloom.x, 1.0);
}

// Cheap O(1) finish: crisp gutter rule + grain + vignette. No blur loops.
uniform vec4 uFin;   // x=grain, y=vignette, z=streams, w=absTime
out vec4 fragColor;
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
void main(){
    vec2 uv = vUV.st;
    vec3 col = texture(sTD2DInputs[0], uv).rgb;
    float nC = clamp(uFin.z, 1.0, 3.0);
    // re-assert crisp hairline gutters between channels at full res
    float lx = fract(uv.x * nC);
    float aa = fwidth(lx);
    float rule = smoothstep(aa*2.0, 0.0, min(lx, 1.0-lx));
    col *= 1.0 - 0.5*rule;          // thin dark separator
    // vignette
    vec2 p = uv - 0.5;
    float vig = 1.0 - uFin.y * smoothstep(0.35, 0.85, length(vec2(p.x*0.6, p.y)));
    col *= vig;
    // grain
    col += (hash21(uv*uTDOutputInfo.res.zw + uFin.w*60.0)-0.5) * 0.012 * uFin.x;
    fragColor = vec4(col, 1.0);
}
